"""Aggregation helpers.

Each function takes a list of parsed log records and returns a
summary. Records are expected to have at least the keys produced by
parser.parse_line (timestamp, level, message); functions that need
additional structure are explicit in their docstrings.
"""

from collections import Counter, defaultdict


def count_by_level(records) -> dict:
    """Return a dict mapping each observed log level to its count.
    Records missing a `level` key are skipped.
    """
    counts = Counter()
    for record in records:
        level = record.get("level")
        if level is None:
            continue
        counts[level] += 1
    return dict(counts)


def count_by_hour(records) -> dict:
    """Return a dict mapping each observed hour (0-23) to its count.

    Hours are derived from the `timestamp` field: the substring
    between the 'T' separator and the next ':'. Records whose
    timestamp doesn't contain a parseable hour are skipped.
    """
    counts = defaultdict(int)
    for record in records:
        ts = record.get("timestamp")
        if not isinstance(ts, str):
            continue
        if "T" not in ts:
            continue
        try:
            hour_str = ts.split("T", 1)[1].split(":", 1)[0]
            hour = int(hour_str)
        except (ValueError, IndexError):
            continue
        if not (0 <= hour <= 23):
            continue
        counts[hour] += 1
    return dict(counts)


def top_n_messages(records, n: int) -> list:
    """Return the n most common (message, count) tuples in descending
    order. Ties are broken by first-appearance order.
    """
    if n <= 0:
        return []
    counts = Counter()
    for record in records:
        msg = record.get("message")
        if not isinstance(msg, str):
            continue
        counts[msg] += 1
    return counts.most_common(n)


def summarize(records) -> dict:
    """Compose the three aggregations into a single summary dict.
    Useful as a one-call report.

    Returns: {"total": N, "by_level": {...}, "by_hour": {...}, "top_5": [...]}
    """
    return {
        "total": len(records),
        "by_level": count_by_level(records),
        "by_hour": count_by_hour(records),
        "top_5": top_n_messages(records, 5),
    }

setupContent.tests/test_parser.py:
"""Tests for src.parser.

Covers parse_line. Does NOT cover parse_file or count_lines.
"""

import unittest

from src.parser import parse_line


class TestParseLine(unittest.TestCase):
    def test_basic_well_formed_line(self):
        result = parse_line("2026-05-25T14:30:01  INFO  user login succeeded")
        self.assertEqual(
            result,
            {
                "timestamp": "2026-05-25T14:30:01",
                "level": "INFO",
                "message": "user login succeeded",
            },
        )

    def test_blank_line_returns_none(self):
        self.assertIsNone(parse_line(""))
        self.assertIsNone(parse_line("   "))
        self.assertIsNone(parse_line("\n"))

    def test_message_can_contain_spaces(self):
        result = parse_line("2026-05-25T14:30:01  WARN  retry 2 of 5")
        self.assertEqual(result["message"], "retry 2 of 5")

    def test_unparseable_line_returns_none(self):
        self.assertIsNone(parse_line("not a log line"))
        self.assertIsNone(parse_line("oneword"))

    def test_single_space_separation_fails(self):
        # Parser requires 2+ spaces between fields.
        self.assertIsNone(parse_line("2026-05-25T14:30:01 INFO user login"))


if __name__ == "__main__":
    unittest.main()

setupContent.tests/test_validator.py:
"""Tests for src.validator.

Covers validate_timestamp + validate_level. Does NOT cover
validate_message or validate_record.
"""

import unittest

from src.validator import validate_level, validate_timestamp


class TestValidateTimestamp(unittest.TestCase):
    def test_iso_date_passes(self):
        self.assertTrue(validate_timestamp("2026-05-25"))

    def test_iso_datetime_passes(self):
        self.assertTrue(validate_timestamp("2026-05-25T14:30:01"))

    def test_iso_datetime_with_offset_passes(self):
        self.assertTrue(validate_timestamp("2026-05-25T14:30:01+08:00"))

    def test_iso_datetime_with_z_passes(self):
        self.assertTrue(validate_timestamp("2026-05-25T14:30:01Z"))

    def test_malformed_fails(self):
        self.assertFalse(validate_timestamp("25-05-2026"))
        self.assertFalse(validate_timestamp("yesterday"))
        self.assertFalse(validate_timestamp(""))

    def test_non_string_fails(self):
        self.assertFalse(validate_timestamp(None))
        self.assertFalse(validate_timestamp(20260525))


class TestValidateLevel(unittest.TestCase):
    def test_all_canonical_levels_pass(self):
        for level in ("DEBUG", "INFO", "WARN", "ERROR", "FATAL"):
            self.assertTrue(validate_level(level), f"{level} should be valid")

    def test_lowercase_fails(self):
        self.assertFalse(validate_level("info"))
        self.assertFalse(validate_level("debug"))

    def test_unknown_level_fails(self):
        self.assertFalse(validate_level("VERBOSE"))
        self.assertFalse(validate_level("CRITICAL"))

    def test_empty_fails(self):
        self.assertFalse(validate_level(""))

    def test_non_string_fails(self):
        self.assertFalse(validate_level(None))


if __name__ == "__main__":
    unittest.main()
